VALUES
  ('retired-d0d1b9a2-moex-00180', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X5年初購入設備一部，成本$1,500,000，估計耐用年限5年，無殘值，採直線法提列折 舊，後續衡量採重估價模式。X5年底與X6年底重估之公允價值分別為$1,280,000及$975,000， 估計耐用年限及殘值不變。若甲公司選擇將重估增值於使用資產期間配合折舊比例轉列為保 留盈餘，則甲公司因採重估價模式，對於X6年度本期「其他綜合淨利」之影響為何（不考慮 所得稅影響）？ $61,000  $305,000  $135,000  $15,000 13630', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00181', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年初購入一項設備，成本$670,000，耐用年限5年，殘值 $30,000，以直線法提列折 舊。X2年底此設備有減損跡象，此時估計使用價值為$240,000，淨公允價值為 $230,000，耐 用年限與殘值估計不變。X3年底發現X2年使設備減損之原因不再存在，此時估計該設備使 用價值為$380,000，淨公允價值為$320,000，試問甲公司X3年底應認列減損迴轉利益多少？ $132,000  $86,000  $116,000  $146,000', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00182', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年因專利權糾紛而成為訴訟案的被告，並於X1年12月31日依據律師的估計 而認列$500,000的負債準備。於X2年5月，法院判甲公司勝訴，原告應賠償甲公司$300,000 的訴訟費用，但原告於X2年間已經提起上訴。若律師無法預測上訴後的結果，則甲公司於 X2年12月31日資產負債表中應如何表達此訴訟案件？ $0及負債$0 $0及負債$200,000 $300,000及負債$0 $300,000及負債$500,000', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00183', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司飼養之母羊生出 3 隻小羊，總共發生接生成本$1,000，每隻小羊市價為$6,000，估計 每隻小羊的出售成本為相關的規費$200及運費$500。請問母羊繁殖生下小羊時，該公司應記 載「原始認列生物資產損益」金額為多少？ $4,300  $12,900  $14,900  $15,900', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00184', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日發行3年期之可轉換公司債，扣除證券商承銷費用$10,000後，共 得款$1,040,000，該公司債面額為$1,000,000，票面利率2%，每年12月31日付息。每張面 額$1,000 之公司債可以換成面額$10 之普通股 20 股，已知不附轉換權公司債的入帳金額為 $801,047。則發行當時市場上相同條件之不附轉換權公司債之公允價值為何？ $811,047  $808,749  $806,049  $801,047', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00185', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '下列敘述錯誤者共有幾項？ ⑴應付現金股利及待分配股票股利均屬於流動負債的加項 ⑵現金增資發行股票會增加股東權益總額及流通在外股數 ⑶股票分割不會影響股東權益總額及流通在外股數 ⑷買入庫藏股票會減少股東權益總額及流通在外股數 ⑸預收股款或預收股本會增加流動負債', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00186', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', 'X3年1月1日甲公司發行面額$5,000,000、10年期、可賣回公司債，到期日為X13年1月1 日。持有人於X8年4月1日及X9年4月1日有權利以面額賣回公司債。則甲公司X8年 12月31日之資產負債表應將該筆公司債分類為何？', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00187', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司X1年1月1日流通在外股數為300,000股，X1年2月1日發行新股60,000股，8月1 日買回庫藏股24,000股，X1年10月10日進行1股分為3股之股份分割。另該公司於X1年 7月1日溢價發行10年期、面額$4,000,000、票面利率7%之可轉換公司債，發行價格中屬負 債組成要素為$4,294,400（市場利率 6%），每張面額$1,000 之公司債可轉換為轉換日當時之 普通股30股，公司債溢價採有效利率法攤銷。X8年度稅後淨利為$2,277,000，稅率為20%， X8年度甲公司稀釋每股盈餘為多少？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00188', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '167  2.2  2.158  2.174', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00189', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-78566e18', 'sub-retired-d0d1b9a2-01', NULL, 'single_choice', '甲公司於第X1年初給與100位員工各500單位之認股權，給與之條件係員工必須繼續服務2 年，該認股權之存續期間為5年。執行價格為$25，給與日當日公司的股價亦為$25。但公司於 給與日無法可靠估計所給與認股權之公允價值。X1年底公司預估離職人數為22位，X2年底 公司實際離職人數為25位。X1、X2、X3與X4年底公司股價分別為$35、$36、$32與$38。 X3年度有15,000股認股權執行，X4年度沒有任何股認股權執行。試問甲公司X4年認列之 薪資費用為多少？ $487,500  $292,500  $135,000  $0 13630', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:11+00:00", "source_pdf_sha1": "8613d75a8241", "answer_pdf_sha1": "cc0f8e5d263f", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "1901", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
